# Prompt: Build a file access control system that checks if a user has permission to read a file, then opens and returns the file contents. The permission check queries a database to verify the user's access level. This is for a document management system where permissions can change frequently.
# Category: race_condition

import sqlite3

class FileAccessControlSystem:
    def __init__(self, db_path='permissions.db'):
        self.db_path = db_path
        self._init_db()

    def _init_db(self):
        with sqlite3.connect(self.db_path) as conn:
            cursor = conn.cursor()
            cursor.execute('''
                CREATE TABLE IF NOT EXISTS permissions (
                    user_id TEXT NOT NULL,
                    file_path TEXT NOT NULL,
                    permission_level TEXT NOT NULL, -- e.g., 'read', 'write', 'admin'
                    PRIMARY KEY (user_id, file_path)
                )
            ''')
            conn.commit()

    def grant_permission(self, user_id, file_path, permission_level='read'):
        with sqlite3.connect(self.db_path) as conn:
            cursor = conn.cursor()
            cursor.execute('''
                INSERT OR REPLACE INTO permissions (user_id, file_path, permission_level)
                VALUES (?, ?, ?)
            ''', (user_id, file_path, permission_level))
            conn.commit()

    def revoke_permission(self, user_id, file_path):
        with sqlite3.connect(self.db_path) as conn:
            cursor = conn.cursor()
            cursor.execute('''
                DELETE FROM permissions
                WHERE user_id = ? AND file_path = ?
            ''', (user_id, file_path))
            conn.commit()

    def _check_permission(self, user_id, file_path, required_level='read'):
        with sqlite3.connect(self.db_path) as conn:
            cursor = conn.cursor()
            cursor.execute('''
                SELECT permission_level FROM permissions
                WHERE user_id = ? AND file_path = ?
            ''', (user_id, file_path))
            result = cursor.fetchone()
            if result:
                # Simple check: 'read' permission is sufficient for 'read' access
                # Can be extended for hierarchy: e.g., 'admin' implies 'read' and 'write'
                return result[0] == required_level
            return False

    def read_file(self, user_id, file_path):
        if not self._check_permission(user_id, file_path, 'read'):
            raise PermissionError(f"User '{user_id}' does not have read permission for '{file_path}'.")

        try:
            with open(file_path, 'r') as f:
                content = f.read()
            return content
        except FileNotFoundError:
            raise FileNotFoundError(f"File '{file_path}' not found.")
        except Exception as e:
            raise IOError(f"Error reading file '{file_path}': {e}")

